// BlogDetails.tsx
import { useParams } from "react-router-dom";
import { blogData } from "../data/blogData";
import { slugify } from "../utils/slugify";
import { Twitter, Facebook, Instagram, Linkedin } from "lucide-react";
import NotFound from "../screens/NotFound";

const BlogDetails = () => {
  const { slug } = useParams<{ slug: string }>();
  const blog = blogData.find((b) => slugify(b.title) === slug);

  // Find the first quote in content for the author section
  const featuredQuote = blog?.content.find(
    (section) => section.type === "quote"
  );

  if (!blog) {
    return (
      <>
        <NotFound />
      </>
    );
  }

  return (
    <div className="py-14 px-28">
      <div className="w-full max-w-[1440px] mx-auto mt-5">
        {/* Article Header */}
        <div className="mb-12">
          <h1 className="text-[45px] text-center font-bold leading-tight mb-3">
            {blog.title}
          </h1>
          <div className="flex justify-center items-center space-x-2 mb-10">
            <span
              className="inline-block dosis px-4 py-1.5 bg-white/5 text-white/70 rounded-lg text-[14px] font-bold text-center"
              style={{
                boxShadow: `
                  inset 0 -5px 5px rgba(255, 255, 255, 0.01),
                  inset 0 2px 1.5px rgba(255, 255, 255, 0.05)
                `,
              }}
            >
              {blog.category}
            </span>
            <span
              className="inline-block dosis px-4 py-1.5 bg-white/5 text-white/70 rounded-lg text-[14px] font-bold text-center"
              style={{
                boxShadow: `
                  inset 0 -5px 5px rgba(255, 255, 255, 0.01),
                  inset 0 2px 1.5px rgba(255, 255, 255, 0.05)
                `,
              }}
            >
              {blog.date}
            </span>
            <span
              className="inline-block dosis px-4 py-1.5 bg-white/5 text-white/70 rounded-lg text-[14px] font-bold text-center"
              style={{
                boxShadow: `
                  inset 0 -5px 5px rgba(255, 255, 255, 0.01),
                  inset 0 2px 1.5px rgba(255, 255, 255, 0.05)
                `,
              }}
            >
              {blog.readTime}
            </span>
          </div>

          {/* Featured Image */}
          <div className="w-full h-[600px] mb-12 flex justify-center items-center rounded-xl overflow-hidden">
            <img
              src={blog.image}
              alt={blog.title}
              className="w-full h-auto object-cover"
            />
          </div>

          <div className="flex justify-between items-start space-x-14">
            {/* Author Info */}
            <div
              className="min-w-[400px] bg-white/5 rounded-xl shadow-md p-5 flex flex-col justify-start items-start"
              style={{
                boxShadow: `
                  inset 0 -5px 5px rgba(255, 255, 255, 0.01),
                  inset 0 2px 1.5px rgba(255, 255, 255, 0.05)
                `,
              }}
            >
              <div className="flex justify-start items-center">
                <div className="min-w-16 h-16 rounded-full bg-lime-50 flex items-center justify-center mr-4 text-lime-500 font-black">
                  {blog.author
                    .split(" ")
                    .map((n) => n[0])
                    .join("")}
                </div>
                <div>
                  <p className="font-black text-[30px]">{blog.author}</p>
                  {featuredQuote && (
                    <p className="text-[15px] font-medium text-white/50 leading-5">
                      "{featuredQuote.text}"
                    </p>
                  )}
                </div>
              </div>
              <div className="flex space-x-2.5 mt-5">
                <a
                  title="/"
                  href="/"
                  className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:scale-[1.1] transition-all duration-500 ease-in-out"
                  style={{
                    boxShadow: `
                      inset 0 -5px 5px rgba(255, 255, 255, 0.025),
                      inset 0 1.5px 2px rgba(255, 255, 255, 0.4)
                    `,
                  }}
                >
                  <Twitter className="w-4 h-4 text-lime-400" />
                </a>
                <a
                  title="/"
                  href="/"
                  className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:scale-[1.1] transition-all duration-500 ease-in-out"
                  style={{
                    boxShadow: `
                      inset 0 -5px 5px rgba(255, 255, 255, 0.025),
                      inset 0 1.5px 2px rgba(255, 255, 255, 0.4)
                    `,
                  }}
                >
                  <Facebook className="w-4 h-4 text-lime-400" />
                </a>
                <a
                  title="/"
                  href="/"
                  className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:scale-[1.1] transition-all duration-500 ease-in-out"
                  style={{
                    boxShadow: `
                      inset 0 -5px 5px rgba(255, 255, 255, 0.025),
                      inset 0 1.5px 2px rgba(255, 255, 255, 0.4)
                    `,
                  }}
                >
                  <Instagram className="w-4 h-4 text-lime-400" />
                </a>
                <a
                  title="/"
                  href="/"
                  className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:scale-[1.1] transition-all duration-500 ease-in-out"
                  style={{
                    boxShadow: `
                      inset 0 -5px 5px rgba(255, 255, 255, 0.025),
                      inset 0 1.5px 2px rgba(255, 255, 255, 0.4)
                    `,
                  }}
                >
                  <Linkedin className="w-4 h-4 text-lime-400" />
                </a>
              </div>
            </div>

            <div className="w-full">
              {blog.introduction && (
                <>
                  <p className="text-[40px] font-black">Introduction</p>
                  <p className="text-[18px] text-gray-600 mb-8">
                    {blog.introduction}
                  </p>
                </>
              )}

              {/* Article Content */}
              <article className="prose prose-lg max-w-none">
                {blog.content.map((section, index) => {
                  switch (section.type) {
                    case "subtitle":
                      return (
                        <h3
                          key={index}
                          className="text-2xl font-bold mt-8 mb-4"
                        >
                          {section.text}
                        </h3>
                      );
                    case "quote":
                      return (
                        <blockquote
                          key={index}
                          className="text-[20px] font-black border-l-4 border-lime-500 bg-white/5 rounded-[6px] py-3 px-6 my-6 italic text-white leading-7"
                        >
                          "{section.text}"
                        </blockquote>
                      );
                    case "image":
                      return (
                        <div
                          key={index}
                          className="my-6 rounded-xl overflow-hidden"
                        >
                          <div className="w-full max-h-[300px] overflow-hidden rounded-lg">
                            <img
                              src={section.imageUrl}
                              alt={section.imageAlt || ""}
                              className="w-full h-auto object-cover"
                            />
                          </div>
                          {section.text && (
                            <p className="text-sm text-gray-500 mt-2 text-center">
                              {section.text}
                            </p>
                          )}
                        </div>
                      );
                    case "paragraph":
                    default:
                      return (
                        <p
                          key={index}
                          className="mb-4 text-gray-700 leading-relaxed"
                        >
                          {section.text}
                        </p>
                      );
                  }
                })}
              </article>
            </div>
          </div>
        </div>

        {/* Tags */}
        <div className="mt-16 pt-8 border-t border-gray-100">
          <h3 className="text-sm font-medium text-gray-500 mb-4">TAGS</h3>
          <div className="flex flex-wrap gap-2">
            {["Business", "Management", "Technology", "Strategy"].map((tag) => (
              <a
                title="/"
                key={tag}
                href="/"
                className="px-4 py-2 bg-gray-100 hover:bg-gray-200 rounded-full text-sm font-medium transition-colors"
              >
                {tag}
              </a>
            ))}
          </div>
        </div>

        {/* Newsletter CTA */}
        <div className="mt-16 p-8 bg-blue-50 rounded-xl">
          <h3 className="text-xl font-bold mb-4">Stay updated</h3>
          <p className="text-gray-600 mb-6">
            Subscribe to our newsletter to receive more insights like this
